INSERT INTO public.photos VALUES (22116, 'Gasolinera &quot;Los Enlaces&quot; 1959', 'Imagen de la original estaciâ”œâ”‚n de servicio "Los Enlaces" como concesionario de la empresa CAMPSA para la distribuciâ”œâ”‚n de derivados del petrâ”œâ”‚leo. Su denominaciâ”œâ”‚n provenâ”œÂ¡a del estratâ”œÂ®gico lugar en que estaba ubicada, junto a la rotonda de conexiâ”œâ”‚n entre la carretera de los enlaces Logroâ”œâ–’o-Madrid-Valencia (a la derecha) y la carretera de Madrid. Un par de aâ”œâ–’os mâ”œÃ­s tarde serâ”œÂ¡a profundamente reformada y ampliada por Josâ”œÂ® de Yarza Garcâ”œÂ¡a. Fuente visual: "Zaragoza. Arquitectura siglo XX" (Jesâ”œâ•‘s Martâ”œÂ¡nez Verâ”œâ”‚n).', 1959, 1959, 1959, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65040600, -0.91932300, '0101000020E61000004DBD6E11186BEDBFA38FF98040D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22451872032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22451872032.webp', 'https://www.flickr.com/photos/zaragozaantigua/22451872032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22282, 'Delicias 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1968. "Vistas desde un edificio." Vista desde la altura de los veteranos bloques de vivienda de la actual calle Demetrio Galâ”œÃ­n Bergua con Avenida de Madrid. En esta ocasiâ”œâ”‚n, la imagen se ha tomado girando la câ”œÃ­mara hacia la izquierda para capturar un panorama de la ciudad por aquellos derroteros. Asâ”œÂ¡, en primerâ”œÂ¡simo plano, aparecen los tejados de la fâ”œÃ­brica Criado y Lorenzo. Detrâ”œÃ­s de los inmediatos campos de herbâ”œÃ­ceas, se escalonan ascendiendo hacia Duquesa de Villahermosa los edificios del "Grupo Alfâ”œÂ®rez Rojas", y el nuevo colegio Padre Enrique de Ossâ”œâ”‚, inaugurado un aâ”œâ–’o antes.', 1968, 1968, 1968, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64674900, -0.91596300, '0101000020E6100000D3122BA3914FEDBF40DCD5ABC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15038024487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15038024487.webp', 'https://www.flickr.com/photos/zaragozaantigua/15038024487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22287, 'Los Enlaces 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1968. "Vistas desde un edificio." Vista desde la altura de los veteranos bloques de vivienda de la actual calle Demetrio Galâ”œÃ­n Bergua con Avenida de Madrid, desde los que se tenâ”œÂ¡a buena perspectiva de la zona limâ”œÂ¡trofe con la carretera de los enlaces, o Vâ”œÂ¡a Hispanidad. En primer plano, los vallados jardines de acceso a la fâ”œÃ­brica de Criado y Lorenzo. Mâ”œÃ­s adelante, la rotonda que permitâ”œÂ¡a el acceso al Barrio de Oliver y a la carretera de Madrid (hacia la izquierda). Allâ”œÂ¡ estaba desde 1963 la moderna y caracterâ”œÂ¡stica Estaciâ”œâ”‚n de Servicio de Los Enlaces. A su derecha, los bloques del "Grupo de Viviendas Arzobispo Domenech" y el nuevo colegio de las monjas Claretianas. Al fondo, el Barrio de Oliver.', 1968, 1968, 1968, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64993600, -0.91845500, '0101000020E610000032207BBDFB63EDBF1C3F541A31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15201155146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15201155146.webp', 'https://www.flickr.com/photos/zaragozaantigua/15201155146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22480, 'Los Enlaces 1964', 'Imagen capturada desde el interior de la vanguardista estructura proyectada por el arquitecto Josâ”œÂ® de Yarza Garcâ”œÂ¡a como "umbrâ”œÃ­culo desmontable para estacionamiento de vehâ”œÂ¡culos gigantes" (garaje de camiones y autobuses) anexo a la estaciâ”œâ”‚n de servicio de los Enlaces. Al fondo, el Enlace de Carreteras (Madrid, Logroâ”œâ–’o y Valencia), aâ”œâ–’os despuâ”œÂ®s redenominado Vâ”œÂ¡a de la Hispanidad. Hacia la derecha, fuera de plano, la carretera de Madrid. Fuente visual: arch. J. de Yarza', 1964, 1964, 1964, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65051500, -0.91949400, '0101000020E61000007EC85BAE7E6CEDBF5A47551344D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37297648554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37297648554.webp', 'https://www.flickr.com/photos/zaragozaantigua/37297648554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22217, 'P.â”¬â•‘ de Fernando el Catâ”œâ”‚lico c.1951', 'Imagen capturada desde la altura del moderno inmueble del nâ”¬â•‘ 55 del paseo de Fernando el Catâ”œâ”‚lico, en ese momento todavâ”œÂ¡a el â”œâ•‘ltimo construido en esta perifâ”œÂ®rica zona de ensanche de la ciudad. A la izquierda e inmediata, la marista Editorial Luis Vives SA, proyectada por los arquitectos Regino y Josâ”œÂ® Borobio, con el arranque de su referencial torre en proceso de construcciâ”œâ”‚n. Al fondo, tras el acceso al parque de Primo de Rivera, la Residencia Sanitaria "Josâ”œÂ® Antonio" en obras, en el nuevo y despejado paseo de Isabel la Catâ”œâ”‚lica, donde destaca el novâ”œÂ¡simo tendido de la tranviaria lâ”œÂ¡nea 15. Casablanca. En el centro de la imagen, arbolado bulevar del paseo que desemboca en la plaza del Emperador Carlos V, donde destaca la torre e instalaciones de la Feria de Zaragoza, junto a la terminal de la lâ”œÂ¡nea del tranvâ”œÂ¡a 11. Parque. Detrâ”œÃ­s, campos de cultivo surtidos por la acequia de la Romareda. A la derecha, solares en barbecho del tramo final del paseo, y traseras del bloque pastilla de los inmuebles de los nâ”œâ•‘meros 31-39 de la calle del Arzobispo Apaolaza, diseâ”œâ–’ados por el arquitecto Antonio Châ”œâ”‚liz Alcrudo.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.63832200, -0.89727400, '0101000020E6100000A5A2B1F677B6ECBF9E280989B4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48271528496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48271528496.webp', 'https://www.flickr.com/photos/zaragozaantigua/48271528496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22563, 'Valdefierro 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 16/04/1974. Desde la dâ”œÂ®cada de 1950 llega a la barriada de Valdefierro un aluviâ”œâ”‚n de empobrecidos campesinos de Andalucâ”œÂ¡a, Extremadura, Castilla, y de las zonas de Calatayud y Daroca. Se parcelan fincas y construyen de forma alegal (Valdefierro, oficialmente, no existâ”œÂ¡a), las viviendas en forma de parcelitas de una-dos plantas. No habâ”œÂ¡a servicios pâ”œâ•‘blicos: el agua se cogâ”œÂ¡a del Canal Imperial, la acequia o se compraba a los aguadores; el alcantarillado eran las calles, descampados, y pozos ciegos; la luz provenâ”œÂ¡a de velas, candiles y carbureros; el calor, de leâ”œâ–’a, carbâ”œâ”‚n, petrâ”œâ”‚leo. En 1957 llega la electricidad y un primitivo alumbrado pâ”œâ•‘blico. Luego, se construye el edificio que albergarâ”œÃ­ la casa parroquial y el Cine Ideal (en su platea se construirâ”œÃ­n las primeras escuelas oficiales), y el edificio del comedor del Auxilio Social. El barrio no tenâ”œÂ¡a nombres en las calles, y se decide nombrarlas con constelaciones, signos zodiacales y planetas del sistema solar. El 12 de octubre de 1961 se consagra la Parroquia de Nuestra Seâ”œâ–’ora de Lourdes del barrio de Valdefierro de la Inmaculada. En 1971, Valdefierro es reconocido oficialmente. El movimiento vecinal reclama servicios dignos, y protagoniza la revuelta popular de marzo de 1974, para reclamar transporte pâ”œâ•‘blico. En la imagen, la barriada de Valdefierro desde las alturas cercanas a la calle Antares. Abajo, la Parroquia de Nâ”¬Â¬ Seâ”œâ–’ora de Lourdes, en la calle Federico Ozanam. A la izquierda, la calle Plutâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.63963700, -0.93091900, '0101000020E6100000663387A416CAEDBFE1270EA0DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15228335349.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15228335349.webp', 'https://www.flickr.com/photos/zaragozaantigua/15228335349/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22728, 'Vâ”œÂ¡a Hispanidad c.1978', 'Aâ”œÂ®rea visual del sector comprendido entre el "Manicomio" (hacia la derecha, fuera de plano) y la Vâ”œÂ¡a de la Hispanidad. Centra la imagen el complejo del colegio "Padre Enrique de Ossâ”œâ”‚", de la Compaâ”œâ–’â”œÂ¡a de Santa Teresa de Jesâ”œâ•‘s. Junto a â”œÂ®l, algunos bloques del "Grupo Alfâ”œÂ®rez Rojas". Al otro lado de la Vâ”œÂ¡a de la Hispanidad, entorno y pinar montaraz y silvestre que luego serâ”œÂ¡a domeâ”œâ–’ado y urbanizado. A su derecha, los grandes bloques de las calles Roger de Flor, y Demetrio Galâ”œÃ­n Bergua. Aparece un buen pedazo del terreno vallado que era utilizado, entre otras cosas, como provisional campo de balompiâ”œÂ® de duro firme ("Campo de Nâ”¬Â¬ Sâ”¬Â¬ de Guadalupe"), hasta que en 1983 comenzâ”œâ”‚ el planteamiento urbanâ”œÂ¡stico de la zona, y estos terrenos fueron destinados a equipamientos sociales (Colegio Pâ”œâ•‘blico "Ciudad de Zaragoza", y Pabellâ”œâ”‚n Deportivo Municipal del mismo nombre). En primer plano, los bloques de la calle Villa de Andorra. Fuente visual: Vicente Modesto Locual.', 1978, 1978, 1978, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64669400, -0.91505000, '0101000020E6100000B98D06F01648EDBF7C4276DEC6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30610412216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30610412216.webp', 'https://www.flickr.com/photos/zaragozaantigua/30610412216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22790, 'Torre Burbano 1970', 'Ortofoto de 1970 en la que se delimita el perâ”œÂ¡metro de los terrenos de la finca de Tomâ”œÃ­s Burbano, al sur de la Vâ”œÂ¡a Hispanidad, frente al grupo sindical Alfâ”œÂ®rez Rojas. Allâ”œÂ¡ se construyâ”œâ”‚ entre 1977 y 1979 la urbanizaciâ”œâ”‚n Parque Hispanidad, segâ”œâ•‘n proyecto de 776 viviendas de Emilio Molinero y Juan Antonio Larriba, de 1974. El complejo se completâ”œâ”‚ aâ”œâ–’os despuâ”œÂ®s en el resto de terrenos de la misma finca, con el nombre de Parque Hispanidad II. La numeraciâ”œâ”‚n inserta en la foto corresponde a este listado: 1. Ciudad Escolar Pignatelli 2. Colegio Mayor Azaila 3. Renault 4. Stadium Delicias 5. Orfanato Nacional Agustina de Aragâ”œâ”‚n 6. Grupo Alfâ”œÂ®rez Rojas Fuente: "Parque Hispanidad, un urbanismo de transiciâ”œâ”‚n en Zaragoza", La Cadiera, 2010.', 1970, 1970, 1970, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64745100, -0.91916000, '0101000020E6100000D252793BC269EDBF9961A3ACDFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41112057242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41112057242.webp', 'https://www.flickr.com/photos/zaragozaantigua/41112057242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22927, 'Ctra. de Madrid 1983', 'Aâ”œÂ®rea visual de la empresa "Hispano Carrocera S.A.L.", constituida cuando una parte de los trabajadores de la planta de Van Hool Espaâ”œâ–’a S.A. en Zaragoza, se convirtieron legalmente en trabajadores-propietarios de la fâ”œÃ­brica, orientada a la producciâ”œâ”‚n de autobuses y autocares, manteniendo en una primera fase la licencia Van Holl, y luego creando su propia marca "Hispano Carrocera". En 1992 esta empresa se trasladâ”œâ”‚ al polâ”œÂ¡gono de la Cartuja Baja, y en este espacio hoy se encuentra una de las grandes superficies comerciales de la ciudad. En la imagen, la pastilla ocupada por la planta fabril. Delante de ella, la carretera de Madrid. A la izquierda, la calle de Oriâ”œâ”‚n y el alto donde estaba el reformatorio "El Buen Pastor". A la derecha, la calle de Aldebarâ”œÃ­n. Al fondo, la calle de Federico Ozanam, y viviendas del barrio de Valdefierro. Fuente visual: www.tatahispano.com/', 1983, 1983, 1983, 'Anos 80', 'OLIVER-VALDEFIERRO', 41.64380200, -0.93608800, '0101000020E610000092B245D26EF4EDBFB98C9B1A68D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30492915774.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30492915774.webp', 'https://www.flickr.com/photos/zaragozaantigua/30492915774/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23026, 'Alto Carabinas 1992', 'Imagen del ingreso principal al reformatorio de El Buen Pastor en Valdefierro, edificio proyectado por Josâ”œÂ® y Regino Borobido Ojeda para albergar la nueva Casa Tutelar del Buen Pastor que habrâ”œÂ¡a de sustituir al antiguo reformatorio de Torre Ramona. Puesto en funcionamiento al comienzo de los aâ”œâ–’os cincuenta, fue clausurado en 2006 y sustituido por el moderno Centro de Menores de Juslibol. Abandonado y vandalizado desde su clausura, vecinos organizados de Valdefierro en la Plataforma de Asociaciones para la Recuperaciâ”œâ”‚n del Edificio del Buen Pastor reivindican desde hace aâ”œâ–’os la recuperaciâ”œâ”‚n de este edificio y su entorno con nuevos usos sociales.', 1992, 1992, 1992, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.64403900, -0.93225000, '0101000020E6100000A245B6F3FDD4EDBF9D2CB5DE6FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50203441081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50203441081.webp', 'https://www.flickr.com/photos/zaragozaantigua/50203441081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23185, 'Plaza de la Inmaculada 2004', 'Imagen capturada en la plaza de la Inmaculada Concepciâ”œâ”‚n de Valdefierro y centrada en el edificio que albergara el comedor de la organizaciâ”œâ”‚n falangista "Auxilio Social" de este barrio, cuya construcciâ”œâ”‚n se debiâ”œâ”‚ a la iniciativa del gobernador civil Josâ”œÂ® Manuel Pardo de Santayana. Tenâ”œÂ¡a capacidad para 100 plazas y fue bendecido por el arzobispo Casimiro Morcillo Gonzâ”œÃ­lez el 22 de noviembre de 1956, gestionado por la Secciâ”œâ”‚n Femenina. En 1974 el "Auxilio Social" pasâ”œâ”‚ a ser denominado Ã”Ã‡Â£Instituto Nacional de Asistencia SocialÃ”Ã‡Ã˜ (INAS) y en 1977 quedâ”œâ”‚ adscrito al Ministerio de Trabajo. A la izquierda queda la calle de Federico Ozanam, y al otro lado de la misma la iglesia parroquial de Nuestra Seâ”œâ–’ora de Lourdes. Pocos aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a derribado y sobre su solar el Gobierno de Aragâ”œâ”‚n construyâ”œâ”‚ un Centro para personas mayores gestionado por el Instituto Aragonâ”œÂ®s de Servicios Sociales (IASS) que fue inaugurado en 2011.', 2004, 2004, 2004, 'Siglo XXI', 'OLIVER-VALDEFIERRO', 41.63974900, -0.93079000, '0101000020E6100000F0332E1C08C9EDBF0953944BE3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52461738418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52461738418.webp', 'https://www.flickr.com/photos/zaragozaantigua/52461738418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23690, 'Final Lâ”œÂ¡nea 14 Tranvâ”œÂ¡a 1966', '1966. Colecciâ”œâ”‚n M. Rodrâ”œÂ¡guez. "Final de Lâ”œÂ¡nea 14 en Los Enlaces". En 1949 se inaugurâ”œâ”‚ la Lâ”œÂ¡nea 14 del Tranvâ”œÂ¡a, denominada "Barrio Oliver", hasta el final de la Avenida de Madrid, cerca del denominado "Enlace de Carreteras", donde se emplazâ”œâ”‚ la terminal de Lâ”œÂ¡nea. Se le asignaron los coches mâ”œÃ­s antiguos, y aunque su denominaciâ”œâ”‚n asâ”œÂ¡ lo indicaba, no llegaba hasta el Barrio Oliver, entonces uno de los inframundos de la periferia de la ciudad. Esta Lâ”œÂ¡nea fue clausurada en enero de 1969. En la imagen, el tranvâ”œÂ¡a M104+R104 en la Terminal de Lâ”œÂ¡nea. Al fondo, los bloques de edificios de la calle Demetrio Galâ”œÃ­n Bergua que esquinan con la Avenida de Madrid. Fuente: "Los tranvâ”œÂ¡as de Zaragoza", J. Peâ”œâ–’a/J. M. Valero, DPZ, 1985.', 1966, 1966, 1966, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65060500, -0.91728300, '0101000020E610000015A8C5E0615AEDBF9ACE4E0647D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781646669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781646669.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781646669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23708, 'Hipâ”œâ”‚dromo 1913', 'Foto: Lorenzo Almarza. Una dama con sombrilla sonrâ”œÂ¡e a la câ”œÃ­mara, sentada entre el pâ”œâ•‘blico asistente a una prueba hâ”œÂ¡pica desarrollada en el hipâ”œâ”‚dromo de la carretera de Madrid, propiedad de la Sociedad La Hâ”œÂ¡pica Aragonesa. Mucho mâ”œÃ­s tarde, sobre estos terrenos serâ”œÂ¡a construida la fâ”œÃ­brica de "Criado y Lorenzo". Fuente visual: Archivo de la Diputaciâ”œâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'OLIVER-VALDEFIERRO', 41.64960300, -0.91712200, '0101000020E6100000C8258E3C1059EDBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21286626419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21286626419.webp', 'https://www.flickr.com/photos/zaragozaantigua/21286626419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23712, 'Los Enlaces 1964', 'Imagen de la proto-rotonda de los Enlaces, como estratâ”œÂ®gico punto de convergencia de la avenida de Madrid (al fondo), la carretera de Logroâ”œâ–’o (izquierda), la carretera de Madrid (de donde acaba de llegar el vehâ”œÂ¡culo de primer plano), y la carretera de los Enlaces (derecha). Tras la arboleda de la derecha estaban las instalaciones de la fâ”œÃ­brica de "Criado y Lorenzo" y, al fondo, emerge el nuevo y alto bloque de viviendas del final de la avenida de Madrid, ademâ”œÃ­s de los mâ”œÃ­s pequeâ”œâ–’os bloques del otro lado de la avenida. A la izquierda, justo fuera de plano, estaba la caracterâ”œÂ¡stica Estaciâ”œâ”‚n de Servicio de Los Enlaces, modernizada en equipamientos e instalaciones poco antes de la captura de esta imagen. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64993600, -0.91845500, '0101000020E610000032207BBDFB63EDBF1C3F541A31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24808955930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24808955930.webp', 'https://www.flickr.com/photos/zaragozaantigua/24808955930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23718, 'Los Enlaces 1965', 'Vista en altura centrada en la confluencia carretera de los Enlaces, con la estaciâ”œâ”‚n de servicio diseâ”œâ–’ada por Josâ”œÂ® de Yarza en 1962. Al fondo, el barrio de Las Delicias y la avenida de Madrid. A la derecha, las instalaciones fabriles de Criado y Lorenzo. A lo lejos, torres de la ciudad. Fuente visual: Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65051500, -0.91949400, '0101000020E61000007EC85BAE7E6CEDBF5A47551344D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28561404775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28561404775.webp', 'https://www.flickr.com/photos/zaragozaantigua/28561404775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23719, 'NACORAL 1965', 'Imagen aâ”œÂ®rea del entorno de la juguetera fâ”œÃ­brica NACORAL S.A., en el kilâ”œâ”‚metro 2 del enlace de carreteras Madrid-Valencia, recientemente redenominado Vâ”œÂ¡a de la Hispanidad (en primer plano), y frente al Grupo de Viviendas "Alfâ”œÂ®rez Rojas" (izquierda). Detrâ”œÃ­s de la fâ”œÃ­brica, detalle de la construcciâ”œâ”‚n de los tres bloques de viviendas para trabajadores de la planta, en la calle Monte Buenos Aires, perpendicular a la futura prolongaciâ”œâ”‚n de duquesa de Villahermosa. Al fondo, extensos terrenos del Manicomio, y el barrio de las Delicias. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64370400, -0.91497500, '0101000020E61000000F0BB5A67947EDBFF62686E464D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30905439944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30905439944.webp', 'https://www.flickr.com/photos/zaragozaantigua/30905439944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23723, 'Alto Carabinas 1965', 'Imagen aâ”œÂ®rea capturada sobre el despejado entorno en construcciâ”œâ”‚n del gran edificio propiedad de la Diputaciâ”œâ”‚n Provincial denominado Ciudad Escolar Pignatelli donde, pocos aâ”œâ–’os despuâ”œÂ®s, se trasladarâ”œÂ¡a el hospicio provincial del antiguo Hogar Pignatelli. Inmediatamente tras â”œÂ®l, el Orfanato Nacional "Agustina de Aragâ”œâ”‚n", para niâ”œâ–’as. Abajo, a la izquierda, el tendido del ferrocarril de Caminreal. Al fondo, la Carretera de los Enlaces, con el emboque de la avenida de Madrid, el Grupo de Viviendas "Alfâ”œÂ®rez Rojas", y el barrio de las Delicias. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64271000, -0.92200200, '0101000020E610000048179B560A81EDBFF5673F5244D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31851806255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31851806255.webp', 'https://www.flickr.com/photos/zaragozaantigua/31851806255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23726, 'Roger de Flor 1978', 'Imagen del artificial crâ”œÃ­ter recayente a las calles del Coronel Arce, Roger de Flor, Escultor Palao, y Galâ”œÃ­n Bergua, en una zona de nueva urbanizaciâ”œâ”‚n de Las Delicias sobre una parte de las que fueran grandes instalaciones de la antigua fâ”œÃ­brica de Criado y Lorenzo. A la izquierda, medianeros con los modernos bloques, restos fâ”œâ”‚siles edilicios de aquella â”œÂ®poca, luego sustituidos por otros mâ”œÃ­s acordes con los tiempos. Tiempo despuâ”œÂ®s, este crâ”œÃ­ter fue convertido en accesible y verde glorieta, de nombre Berenguer de Entenza, en homenaje a un medieval linaje del noreste regional. Mâ”œÃ­s recientemente, la calle Coronel Arce ha sido redenominada Agustina Atienza Cobos, nieta pintora de Agustina Zaragoza. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64930000, -0.91665900, '0101000020E6100000A7B052414555EDBF7AA52C431CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32347649874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32347649874.webp', 'https://www.flickr.com/photos/zaragozaantigua/32347649874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23728, 'Escultor Palao 1978', 'Imagen capturada en la chaflanera esquina de las calles Escultor Palao (al frente) y Roger de Flor (perpendicular), donde desde 1974 seguâ”œÂ¡a coleando el "affaire" del polâ”œÂ®mico bloque de Construcciones Cinca SA. (inmediato, a la derecha), del Sr. Fuentes, uno de los emprendedores inmobiliarios cortados al patrâ”œâ”‚n de la â”œÂ®poca, con afecciones directas sobre el derecho a la vivienda de unas 500 familias. A la izquierda, espacio luego habilitado como glorieta Berenguer de Entenza. A continuaciâ”œâ”‚n, bloques esquineros de la calle Nâ”¬Â¬ Sâ”¬Â¬ del Salz, y al fondo, el entronque de Escultor Palao con Mompeâ”œâ”‚n Motos, y Covadonga. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64847400, -0.91644500, '0101000020E6100000A4A5F2768453EDBF35272F3201D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32385512924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32385512924.webp', 'https://www.flickr.com/photos/zaragozaantigua/32385512924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24089, 'Alto Carabinas 1945', 'Imagen capturada durante la veraniega inauguraciâ”œâ”‚n oficial el 26 de julio de 1945 del Orfanato Nacional "Agustina de Aragâ”œâ”‚n", construido por el Ministerio de la Gobernaciâ”œâ”‚n en una despejada zona del Alto de Carabinas. Centra la imagen la inmaculada (por el caracterâ”œÂ¡stico color albino del uniforme oficial del "Movimiento") figura del entonces gobernador civil y jefe provincial de Falange Espaâ”œâ–’ola de las JONS, Eduardo Baeza Alegrâ”œÂ¡a. Le acompaâ”œâ–’an, entre otros, el presidente de la Diputaciâ”œâ”‚n provincial, el alcalde accidental, el vicerrector de la Universidad, el representante del gobernador militar, el jefe de la Policâ”œÂ¡a Armada, el representante del arzobispo, y un alto funcionario de la Direcciâ”œâ”‚n General de Beneficiencia y Obras Sociales. De fondo, la fachada e ingreso principal al orfanato, proyectado por Manuel Martâ”œÂ¡nez Chumillas, con capacidad para un centenar de niâ”œâ–’as huâ”œÂ®rfanas, hijas "de mâ”œÃ­rtires y de hâ”œÂ®roes" nacionalistas, en râ”œÂ®gimen de internado a cargo de una comunidad de madres mercedarias de la Caridad. Sus primeras usuarias provenâ”œÂ¡an del orfanato instalado provisionalmente en el madrileâ”œâ–’o Instituto El Pilar, pues sus originales instalaciones en el Palacio de El Pardo habâ”œÂ¡an sido ocupadas en 1940 para convertirse en la residencia oficial del Jefe del Estado. Fuente visual: Foto Lozano en El Noticiero, del archivo de Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel.', 1945, 1945, 1945, 'Anos 40', 'OLIVER-VALDEFIERRO', 41.64419800, -0.92131600, '0101000020E6100000580229B16B7BEDBF06137F1475D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46036645235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46036645235.webp', 'https://www.flickr.com/photos/zaragozaantigua/46036645235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24444, 'Criado y Lorenzo 1953', 'En 1939 la Compaâ”œâ–’â”œÂ¡a Criado y Lorenzo (fundada en 1911, especializada en correas y gomas) amplâ”œÂ¡a instalaciones mediante la construcciâ”œâ”‚n de un nuevo complejo fabril que incluâ”œÂ¡a 331 viviendas. Estaba previsto hacerlo en el barrio de Cariâ”œâ–’ena, pero el espacio disponible era insuficiente, asâ”œÂ¡ que la nueva ubicaciâ”œâ”‚n fue en el Km. 319 de la carretera de Madrid, junto al Enlace de Carreteras. El nuevo complejo recibiâ”œâ”‚ el nombre de Colonia Fabril de Nuestra Seâ”œâ–’ora del Pilar. En la imagen, acceso principal a la fâ”œÃ­brica desde la carretera de Madrid. A la derecha, la carretera de los Enlaces. A la derecha quedaban las viviendas asociadas al proyecto.', 1953, 1953, 1953, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.64960300, -0.91712200, '0101000020E6100000C8258E3C1059EDBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15053749751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15053749751.webp', 'https://www.flickr.com/photos/zaragozaantigua/15053749751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24468, 'Criado y Lorenzo 1939', 'Fragmento del cuadro que colgaba a la entrada del complejo Criado y Lorenzo, "Colonia fabril de Nuestra Seâ”œâ–’ora del Pilar", representando el proyecto de edificaciâ”œâ”‚n completo de la empresa en 1939. Este conjunto fue inaugurado en 1940, Se trataba de una compaâ”œâ–’â”œÂ¡a de producciâ”œâ”‚n de correas y gomas, cuya anterior sede estaba en la calle de Cariâ”œâ–’ena. Su ubicaciâ”œâ”‚n era la carretera de Madrid (actual avenida), km. 319, junto a Los Enlaces. Fuente: www.facebook.com/photo.php?fbid=420669814765007&set=p...', 1939, 1939, 1939, 'Anos 30', 'OLIVER-VALDEFIERRO', 41.64960300, -0.91712200, '0101000020E6100000C8258E3C1059EDBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20114312144.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20114312144.webp', 'https://www.flickr.com/photos/zaragozaantigua/20114312144/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24503, 'Barrio Oliver 1976', 'Imagen de la manifestaciâ”œâ”‚n de trabajadores de "Vanhool Espaâ”œâ–’a S.A. Zaragoza", realizada como muestra de solidaridad con 12 compaâ”œâ–’eros despedidos por la empresa. Esta manifestaciâ”œâ”‚n comenzâ”œâ”‚ su itinerario periurbano en las instalaciones donde se producâ”œÂ¡an los autobuses y autocares, ubicadas junto a la carretera de Madrid, al fondo, a la derecha. A la izquierda, el alto donde estaba el enorme reformatorio "El Buen Pastor". Aunque no aparecen en la imagen, a los manifestantes acompaâ”œâ–’aba una dotaciâ”œâ”‚n de la Guardia Civil, "para protegerles", aunque ni el desolado lugar, ni la hora (mediodâ”œÂ¡a), auguraban potenciales problemas, salvo alguna insolaciâ”œâ”‚n. Unos dâ”œÂ¡as despuâ”œÂ®s, el Tribunal Central de Trabajo declarâ”œâ”‚ improcedentes los doce despidos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64607900, -0.93239700, '0101000020E6100000B16EBC3B32D6EDBFF2D077B7B2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31262669176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31262669176.webp', 'https://www.flickr.com/photos/zaragozaantigua/31262669176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24506, 'Ctra. de Madrid 1966', 'Aâ”œÂ®rea visual capturada sobre la carretera de Madrid, con una interesante e inmediata panorâ”œÃ­mica de las instalaciones de la empresa de automociâ”œâ”‚n NAZAR, ya integrada en el grupo Barreiros Diesel S.A. A su izquierda, el reformatorio "El Buen Pastor". Detrâ”œÃ­s de ambos, tras la calle de Aldebarâ”œÃ­n, el barrio de Valdefierro, el esbozo de Torre Pajaritos, el Camping municipal, y el Canal Imperial. Al fondo, a la izquierda, los depâ”œâ”‚sitos de agua de Casablanca y el despejado poligono Romareda, hasta la Residencia Sanitaria Josâ”œÂ® Antonio. Fuente visual: Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64380200, -0.93608800, '0101000020E610000092B245D26EF4EDBFB98C9B1A68D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31921673945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31921673945.webp', 'https://www.flickr.com/photos/zaragozaantigua/31921673945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24515, 'Ctra. de Madrid 1948', 'Imagen del moderno complejo industrial de la compaâ”œâ–’â”œÂ¡a "Criado y Lorenzo, C.A." construido junto a la carretera de Madrid, al final del barrio de las Delicias, cerca del Enlace con la carretera de Logroâ”œâ–’o. Su propietario-gerente era â”œÃ¼ngel Lorenzo Izquierdo, y en â”œÂ®l se transformaba la materia prima del caucho en una notable mirâ”œÂ¡ada de objetos de goma y plâ”œÃ­stico, desde esponjas hasta dispositivos auxiliares para maquinaria de precisiâ”œâ”‚n, pasando por los famosos zapatos "Mari-Pi" y las brillantes "katiuskas" o botas de agua. En la imagen, aspecto del complejo fabril capturado desde la carretera de Madrid, en una inmediata y despejada zona en trance de finalizaciâ”œâ”‚n de las infraestructuras previas al proceso de urbanizaciâ”œâ”‚n. A la derecha, el pabellâ”œâ”‚n principal de oficinas con su ajardinado acceso, y detrâ”œÃ­s y a la izquierda, las naves de la fâ”œÃ­brica y las viviendas para obreros. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œÃ­fica de cultura aragonesa", SIPA.', 1948, 1948, 1948, 'Anos 40', 'OLIVER-VALDEFIERRO', 41.64960300, -0.91712200, '0101000020E6100000C8258E3C1059EDBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35141029225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35141029225.webp', 'https://www.flickr.com/photos/zaragozaantigua/35141029225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
