INSERT INTO public.photos VALUES (24833, 'Barrio Oliver 1953', 'Plano del Barrio Oliver de Zaragoza, Dionisio Casaâ”œâ–’al, 1953. Fuente: â”¬Ã­Aquâ”œÂ¡... Zaragoza!, Josâ”œÂ® Blasco Ijazo, 1953.', 1953, 1953, 1953, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65023800, -0.92212000, '0101000020E6100000C4995FCD0182EDBFE84EB0FF3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19236863023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19236863023.webp', 'https://www.flickr.com/photos/zaragozaantigua/19236863023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24838, 'Valdefierro 1965', 'Aâ”œÂ®rea visual de la empresa "Factorâ”œÂ¡as ZANE, S.A." constituida al albur de los beneficios del Polo de Desarrollo de Zaragoza, "para la construcciâ”œâ”‚n, reconstrucciâ”œâ”‚n y reparaciâ”œâ”‚n de autobuses". Su domicilio estaba radicado en la calle Camelia s/n, de la barriada de Valdefierro. En la imagen, la imponente planta aparece entre la lâ”œÂ¡nea del ferrocarril de Caminreal (en primer plano), y las esquineras parcelas de las calles Lucero del Alba, Hortensia, y Camelia (al fondo). Frente a esta fâ”œÃ­brica, al otro lado de las vâ”œÂ¡as, y en unos pocos aâ”œâ–’os, se construirâ”œÂ¡a la nueva Ciudad Escolar Pignatelli. Entre 1996 y 2016 aquâ”œÂ¡ estuvieron ubicadas las instalaciones de "Galletas Asinez, S.A.". Fuente visual: retrobuses.blogspot.com.es/', 1965, 1965, 1965, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.64162700, -0.92434100, '0101000020E61000000F43AB933394EDBF849D62D520D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31156377532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31156377532.webp', 'https://www.flickr.com/photos/zaragozaantigua/31156377532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24842, 'Huâ”œÂ®rfanos de Guerra 1943', 'Dibujo incluido en el anteproyecto de "Edificio en Zaragoza para Huâ”œÂ®rfanos de Guerra", posiblemente ubicado en el Alto Carabinas, presentado a concurso por Teodoro Râ”œÂ¡os Balaguer. No fue realizado Fuente visual: Exposiciâ”œâ”‚n "40 aâ”œâ–’os con Franco" (Zaragoza, 2015).', 1943, 1943, 1943, 'Anos 40', 'OLIVER-VALDEFIERRO', 41.64369600, -0.93263500, '0101000020E6100000D55B035B25D8EDBF73486AA164D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33779048765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33779048765.webp', 'https://www.flickr.com/photos/zaragozaantigua/33779048765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24844, 'Valdefierro 1955', 'Imagen capturada ante la fachada a "abobes a cara vista" de la escuela del barrio de Valdefierro, con el posado colectivo del centenar de niâ”œâ–’os y niâ”œâ–’as atendidos por dos maestras. A comienzos de la dâ”œÂ®cada de los aâ”œâ–’os cincuenta comenzâ”œâ”‚ la andadura de este barrio, resultado de una iniciativa particular que parcelâ”œâ”‚ unos terrenos en lotes vendidos a unos cinco duros el metro cuadrado. Las viviendas que fueron apareciendo eran propias del mâ”œÂ®todo "autoconstrucciâ”œâ”‚n" en materiales baratos y reciclados, como en todos los barrios y barriadas populares surgidos en la ciudad desde principios de siglo. Salvo la calle de Federico de Ozanam, el resto de terrosos viales carecâ”œÂ¡a de nombre. La segunda planta de esta escuela estaba utilizada como almacâ”œÂ®n de productos agrâ”œÂ¡colas, y tenâ”œÂ¡a como vecino un colmado, pero como esto "no era Zaragoza"...', 1955, 1955, 1955, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.63953300, -0.93049000, '0101000020E61000004A29E8F692C6EDBF3CDBA337DCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52372145470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52372145470.webp', 'https://www.flickr.com/photos/zaragozaantigua/52372145470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25998, 'Nacoral 1975', 'Jacinto Olloqui Arellano, socio fundador en 1953 del Centro Espaâ”œâ–’ol de Plâ”œÃ­sticos, puso en marcha la empresa "Jacinto Olloqui Arellano (Industrias Plâ”œÃ­sticas)", luego "NACORAL S.A.", nombre compuesto por un anagrama de su nombre. La fâ”œÃ­brica estaba situada en el tâ”œÂ®rmino de Miralbueno, partidas de San Lamberto, Valdefierro, y Terminillo, en el kilâ”œâ”‚metro 2 del enlace de carreteras Madrid-Valencia, frente al Grupo de Viviendas "Alfâ”œÂ®rez Rojas". A la fâ”œÃ­brica llegaban importados polietileno y poliestireno, que eran transformados en productos del moderno menaje del hogar, y en el elemento referente de la empresa: los juguetes (muâ”œâ–’ecas, balones, pelotas, y una amplia gama de coches y vehâ”œÂ¡culos...) Despuâ”œÂ®s de serle autorizada la importaciâ”œâ”‚n del material "zamack", iniciâ”œâ”‚ la producciâ”œâ”‚n de metâ”œÃ­licos coches a escala, y otros vehâ”œÂ¡culos a motor. Junto a la fâ”œÃ­brica, en 1965, se construyeron tres bloques de viviendas para trabajadores de la empresa, en la calle Monte Buenos Aires. A comienzos de 1982, tras un expediente de regulaciâ”œâ”‚n de empleo, la empresa fue autorizada a cesar sus actividades, y extinguir contratos. Aâ”œâ–’os despuâ”œÂ®s, sobre su apetecible solar, ya recalificado en 1975, se levantarâ”œÂ¡an nuevos bloques de la prolongada calle de Duquesa Villahermosa, junto a la Vâ”œÂ¡a Hispanidad. En la imagen, aâ”œÂ®rea visual del conjunto de la fâ”œÃ­brica, y las viviendas para trabajadores. A la izquierda, el Grupo de Viviendas "Alfâ”œÂ®rez Rojas". Al fondo, el Hospital Psiquiâ”œÃ­trico.', 1975, 1975, 1975, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64370400, -0.91497500, '0101000020E61000000F0BB5A67947EDBFF62686E464D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21684307653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21684307653.webp', 'https://www.flickr.com/photos/zara