INSERT INTO public.photos VALUES (26005, 'Avenida de Madrid 1991', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea del entorno del final de la avenida de Madrid de Zaragoza, en su confluencia con la calle de Demetrio Galâ”œÃ­n Bergua (abajo a la derecha). Fuente: www.facebook.com/photo.php?fbid=1687671948123171&set=...', 1991, 1991, 1991, 'Anos 90', 'OLIVER-VALDEFIERRO', 41.65085300, -0.91740100, '0101000020E6100000912A8A57595BEDBF72C0AE264FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220338200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220338200.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220338200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20974, 'Primera piedra MZA 1856', '"Inauguraciâ”œâ”‚n del ferro-carril de Zaragoza el 12 de mayo de 1856", litografâ”œÂ¡a, 1856. El general Espartero colocâ”œâ”‚ la primera piedra de lo que serâ”œÂ¡a despuâ”œÂ®s la estaciâ”œâ”‚n ferroviaria de Campo Sepulcro, de la Compaâ”œâ–’â”œÂ¡a de los Ferrocarriles de Madrid a Zaragoza y Alicante (MZA). Hasta la inauguraciâ”œâ”‚n de la lâ”œÂ¡nea en 1863, hubo tiempo de reubicar el solar de la estaciâ”œâ”‚n: la ceremonia representada en la imagen se estâ”œÃ­ produciendo "en la orilla del Ebro junto al castillo de la Aljaferâ”œÂ¡a". La demora hizo que la primera estaciâ”œâ”‚n de la ciudad fuese la del Arrabal, de la lâ”œÂ¡nea a Barcelona (1861). En primer tâ”œÂ®rmino, la tienda de campaâ”œâ–’a del arzobispo, con altar y escoltada por gastadores de la milicia nacional; detrâ”œÃ­s, la carpa de las autoridades civiles. En el centro, ceremonia de colocaciâ”œâ”‚n de la primera piedra. Al fondo, el râ”œÂ¡o Ebro. Fuente: El Correo de Ultramar, aâ”œâ–’o 15, 181, 1856.', 1856, 1856, 1856, 'Siglo XIX', 'LA ALMOZARA', 41.65728200, -0.89826100, '0101000020E610000052B648DA8DBEECBFEF1F0BD121D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19867442299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19867442299.webp', 'https://www.flickr.com/photos/zaragozaantigua/19867442299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21072, 'El Ebro y la Aljaferâ”œÂ¡a 1871', '"Zaragoza. Avenida del Ebro. Aspecto de los arrabales la maâ”œâ–’ana del 13 de enero â”œâ•‘ltimo. Vista copiada del natural". Revista La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana, 1871. En la riada de 1871, segâ”œâ•‘n la revista citada, el agua quedâ”œâ”‚ "a unos cinco metros del castillo de la Aljaferâ”œÂ¡a", que vemos a la izquierda del dibujo.', 1871, 1871, 1871, 'Siglo XIX', 'LA ALMOZARA', 41.65758400, -0.89581600, '0101000020E61000002079E75086AAECBFBA2F67B62BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19021124171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19021124171.webp', 'https://www.flickr.com/photos/zaragozaantigua/19021124171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22745, 'A-68 1978', 'Imagen centrada en la moderna autopista que desde el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n conducâ”œÂ¡a vertiginosamente hasta las norteâ”œâ–’as localidades de Bilbao, Pamplona y Logroâ”œâ–’o. Mientras que los antiguos trazados ferroviarios de la ciudad, "tragados" por el desarrollo urbanâ”œÂ¡stico, eran considerados "cicatrices" que constreâ”œâ–’â”œÂ¡an el orgâ”œÃ­nico crecimiento urbano, esta contemporâ”œÃ­nea vâ”œÂ¡a de gran capacidad para el trâ”œÃ­fico rodado, insertada a pocos metros de las antiguas Eras del Campo del Toro, apenas era cuestionada por algunos vecinos organizados que vivâ”œÂ¡an a uno y otro lado de la barrera de los "quitamiedos". A la izquierda, el paâ”œâ–’o oeste del palacio de la Aljaferâ”œÂ¡a, y antiguo trazado ferroviario que enlazaba con la estaciâ”œâ”‚n de la Almozara. Al fondo, grandes bloques de la avenida de Madrid, y las viviendas "militares" de la avenida de Anselmo Clavâ”œÂ®, ademâ”œÃ­s del mar de vâ”œÂ¡as del Portillo. A la derecha, acceso a las Delicias, y calle de Juan XXIII. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65705200, -0.90070600, '0101000020E610000084F3A96395D2ECBFBDE2A9471AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32323568644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32323568644.webp', 'https://www.flickr.com/photos/zaragozaantigua/32323568644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24197, 'La Quâ”œÂ¡mica 1977', 'Imagen de las vâ”œÂ¡as de los trenes que circulaban por la zanja entre el antiguo cuartel de la Aljaferâ”œÂ¡a, y la Industrial Quâ”œÂ¡mica, algunas de cuyas enormes naves aparecen haciendo soleada fachada. Un mercancâ”œÂ¡as aparece estacionado en direcciâ”œâ”‚n a la estaciâ”œâ”‚n de Caminreal, o Delicias. Tras el reciente desmantelamiento del enlace que unâ”œÂ¡a con la estaciâ”œâ”‚n del Norte, por el puente del ferrocarril, este mar de vâ”œÂ¡as permaneciâ”œâ”‚ aâ”œâ•‘n unos aâ”œâ–’os, muy disminuido ya de funciones, hasta su completa desapariciâ”œâ”‚n, mâ”œÃ­s reciente. A la izquierda, ascendiendo el pronunciado desnivel, continuaban las obras de recuperaciâ”œâ”‚n civil del antiguo e inmediato palacio de la Alegrâ”œÂ¡a. Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œÂ®s.', 1977, 1977, 1977, 'Anos 70', 'LA ALMOZARA', 41.65757300, -0.89669300, '0101000020E610000008ABB184B5B1ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26326034673.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26326034673.webp', 'https://www.flickr.com/photos/zaragozaantigua/26326034673/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24199, 'Almozara c.1975', 'Imagen capturada en La Almozara, desde la altura del "paso a nivel" que permitâ”œÂ¡a el cruce de lâ”œÂ¡neas ferroviarias con la lâ”œÂ¡nea de Madrid. El convoy de la imagen proviene de la estaciâ”œâ”‚n de Zaragoza-Arrabal o Norte y estâ”œÃ­ arrastrado por una locomotora diesel "1900" (serie 319), encaminado hacia la estaciâ”œâ”‚n de Zaragoza-Las Delicias para seguir luego en direcciâ”œâ”‚n a Teruel. Desde 1973 esta lâ”œÂ¡nea ya sâ”œâ”‚lo daba servicio de mercancâ”œÂ¡as, y en 1976 fue desmantelada. A la izquierda, vâ”œÂ¡as del enlace hacia La Almozara/Casetas, y fuera de plano, la Industrial Quâ”œÂ¡mica de Zaragoza. A la derecha, en una terraza superior, el intrincado entorno de la Aljaferâ”œÂ¡a, con las construcciones anexas de su larga etapa como cuartel del ejâ”œÂ®rcito. Al fondo de las vâ”œÂ¡as, la reconocible estructura de Piensos CIA (Compaâ”œâ–’â”œÂ¡a Industria Agrâ”œÂ¡cola), y los bloques en construcciâ”œâ”‚n de la confluencia del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, con la calle de Santa Lucâ”œÂ¡a, y el paseo de Echegaray y Caballero. Fuente visual: Severino Rodrâ”œÂ¡guez Garabito, Colecciâ”œâ”‚n del Museo del Ferrocarril de Asturias, a travâ”œÂ®s de www.forotrenes.com/', 1975, 1975, 1975, 'Anos 70', 'LA ALMOZARA', 41.65757300, -0.89669300, '0101000020E610000008ABB184B5B1ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30680782056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30680782056.webp', 'https://www.flickr.com/photos/zaragozaantigua/30680782056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24216, 'Almozara, c.1974', 'Imagen centrada en una locomotora "Mikado" tirando de un convoy por el enlace ferroviario de la Almozara en direcciâ”œâ”‚n al puente del ferrocarril. Al fondo, escenario conformado por las instalaciones de la Industrial Quâ”œÂ¡mica de Zaragoza, en las que destaca un tanque de agua que luce las iniciales de la fâ”œÃ­brica "IQZ", ademâ”œÃ­s de los grandes almacenes de granulados producidos en esa fâ”œÃ­brica e instalaciones del ensacado de esos granulados. lindantes con la calle del Reino y la calle de Pedro I de Aragâ”œâ”‚n. A la izquierda y en paralelo a la calle del Reino queda la calle del Râ”œÂ¡o Duero.', 1974, 1974, 1974, 'Anos 70', 'LA ALMOZARA', 41.65729800, -0.89972000, '0101000020E6100000EDD3F19881CAECBFF4DC425722D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53603593430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53603593430.webp', 'https://www.flickr.com/photos/zaragozaantigua/53603593430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24554, 'La Aljaferâ”œÂ¡a 1987', 'Luis Mâ”œÂ¡nguez. 1987. Imagen del panorama hacia el noroeste desde la torre del Homenaje de la Aljaferâ”œÂ¡a. En primer plano, el entorno al Palacio reciâ”œÂ®n remodelado e inaugurado como sede de las contemporâ”œÃ­neas Cortes de Aragâ”œâ”‚n, aunque aâ”œâ•‘n faltaba bastante para ser lo que hoy es. A la derecha, vâ”œÂ¡as abandonadas del antiguo enlace ferrovario con la Estaciâ”œâ”‚n del Norte, y con la Industrial Quâ”œÂ¡mica, de la que hay visual del perâ”œÂ¡metro de sus abandonadas instalaciones. Al lado, las recientes urbanizaciones surgidas en la Almozara (calles Braulio Foz, Lago, Reino, Pedro I de Aragâ”œâ”‚n...), y el enlace de la Almozara con las Delicias a travâ”œÂ®s de la calle Juan Bautista del Mazo, con tâ”œâ•‘nel incluido, por debajo de la trinchera del enlace de autopistas. A la izquierda, el mar de vâ”œÂ¡as de la antigua Estaciâ”œâ”‚n de Delicias, con el fondo de los grandes bloques de edificios de la Avenida de Navarra, y de los barrios de la Bozada y Monsalud, mâ”œÃ­s altos.', 1987, 1987, 1987, 'Anos 80', 'LA ALMOZARA', 41.65741900, -0.89836800, '0101000020E6100000D4BB783F6EBFECBF6F62484E26D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15815563205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15815563205.webp', 'https://www.flickr.com/photos/zaragozaantigua/15815563205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26051, 'Almozara y Delicias 2006', 'Ortofoto obtenida el 1 de agosto de 2006. Muestra los barrios de La Almozara (arriba) y Las Delicias (abajo). A la izquierda, estaciâ”œâ”‚n ferroviaria Zaragoza Delicias. A la derecha, palacio de La Aljaferâ”œÂ¡a. En el centro, obras de cubrimiento de las vâ”œÂ¡as del ferrocarril, junto al "scalextric" procedente de la calle Iriarte Reinoso, que unâ”œÂ¡a ambos barrios. Fuente: Fuente: Gobierno de Aragâ”œâ”‚n. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciâ”œâ”‚n e Informaciâ”œâ”‚n Territorial de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'LA ALMOZARA', 41.65704700, -0.90250100, '0101000020E6100000F86EF3C649E1ECBFAB77B81D1AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32059299586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32059299586.webp', 'https://www.flickr.com/photos/zaragozaantigua/32059299586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20938, 'La Almozara y mâ”œÃ­s allâ”œÃ­ 1756', 'Plano firmado por Cipriano de la Plaza con una personal representaciâ”œâ”‚n de caminos, acequias, propiedades y referencias edilicias al oeste de la antigua ciudad, centrado en los tâ”œÂ®rminos de riego de Cantalobos, Argamasa y Agullones de la gran acequia de la Almozara, desde la puerta y molino de Sancho, pasando por el convento trinitario calzado de San Lamberto, y hasta la ermita de San Miguel del Tercio. Para una mejor orientaciâ”œâ”‚n geogrâ”œÃ­fica, habrâ”œÂ¡a que rotar el plano 90 grados hacia la izquierda. En GAZA mantenemos la orientaciâ”œâ”‚n original del plano, que permite leer rectamente sus anotaciones y leyenda. Fuente visual: Real Audiencia de Aragâ”œâ”‚n, AHPZ.', 1756, 1756, 1756, 'Siglo XIX', 'LA ALMOZARA', 41.66356700, -0.92112500, '0101000020E610000060E5D022DB79EDBF38DA71C3EFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39355476220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39355476220.webp', 'https://www.flickr.com/photos/zaragozaantigua/39355476220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22837, 'Puerta Sancho c.1983', 'El subpolâ”œÂ¡gono Puerta Sancho (â”œÃ­rea 45) fue aprobado por el Ministerio de la Vivienda en 1974, con once manzanas residenciales y 2.210 viviendas. Su desarrollo efectivo por el planeamiento municipal hubo de esperar hasta los aâ”œâ–’os 80. En la imagen, vista aâ”œÂ®rea de la zona durante la construcciâ”œâ”‚n de los pioneros bloques en lo que hoy es el cruce de la avenida de Pablo Gargallo con la calle de Berna. Junto a ellos destaca el asfaltado, sinuoso y antiguo camino de Monzalbarba, que luego se diluyâ”œâ”‚ entre la rectilâ”œÂ¡nea traza de este ensanche del barrio de La Almozara. En primer tâ”œÂ®rmino, la torre de los Escolapios para convivencias y ejercicios espirituales rodeada de campos de herbâ”œÃ­ceas. A la izquierda, la frondosa extensiâ”œâ”‚n del centro deportivo militar El Soto y el râ”œÂ¡o Ebro, y al fondo y a la derecha, el Palacio de La Aljaferâ”œÂ¡a. Entre ambos espacios, el telâ”œâ”‚n escâ”œÂ®nico de la ciudad.', 1983, 1983, 1983, 'Anos 80', 'LA ALMOZARA', 41.66173500, -0.90382200, '0101000020E610000051F86C1D1CECECBF2DCF83BBB3D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14851381070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14851381070.webp', 'https://www.flickr.com/photos/zaragozaantigua/14851381070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23082, 'Pabellâ”œâ”‚n-Puente 2007', 'Imagen de la construcciâ”œâ”‚n del denominado "Pabellâ”œâ”‚n Puente" sobre el râ”œÂ¡o Ebro, una de las referencias de la Expo 2008 que perdura, aunque aâ”œâ•‘n en busca de su destino, que probablemente serâ”œÃ­ algo relacionado con las nuevas tecnologâ”œÂ¡as, las ciencias del agua, el devenir de los movimientos tectâ”œâ”‚nicos de placas, las nuevas formas de participaciâ”œâ”‚n social... Fue diseâ”œâ–’ado por la arquitecta Zaha Hadid, mide 270 metros, y de noche estâ”œÃ­ cerrado. Al fondo, obras del meandro de Ranillas como local "Transformer". A este lado del râ”œÂ¡o, donde estuvieran las antiguas instalaciones de Pontoneros e Ingenieros de La Almozara, luego convertidas en el privado y exclusivo Club Deportivo Militar "El Soto". Fuente visual: "El urbanismo de la Expo: el Plan de Acompaâ”œâ–’amiento", ExpoAgua Zaragoza 2008, S.A.', 2007, 2007, 2007, 'Siglo XXI', 'LA ALMOZARA', 41.66640400, -0.90506300, '0101000020E61000008E3A3AAE46F6ECBF38F6ECB94CD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18958318003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18958318003.webp', 'https://www.flickr.com/photos/zaragozaantigua/18958318003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
