INSERT INTO public.photos VALUES (23193, 'Milla Digital 2010', 'Foto: Rusolera, diciembre de 2010. Construcciâ”œâ”‚n de los edificios del menguado proyecto Milla Digital, junto a la estaciâ”œâ”‚n ferroviaria Zaragoza-Delicias (a la izquierda) y en un entorno desolador, junto a la avenida Ciudad de Soria. En el centro, dos de los bloques de Etopia (Centro de Arte y Tecnologâ”œÂ¡a), "con espacios de interacciâ”œâ”‚n para co-creaciâ”œâ”‚n y desarrollo de productos/servicios conjuntos". A la derecha, el CIEM (Centro de Incubaciâ”œâ”‚n Empresarial Milla Digital) en el edificio Cero Emisiones, donde los emprendedores "tienen acceso a todos los servicios avanzados del centro, como orientaciâ”œâ”‚n estratâ”œÂ®gica, talleres de generaciâ”œâ”‚n de ideas, seminarios de creaciâ”œâ”‚n de cultura creativa, acceso a fuentes de financiaciâ”œâ”‚n, encuentros con Business Angels y entidades de capital semilla/riesgo". No cabe mâ”œÃ­s rimbombancia. Fuente: zaragozaciudad.net/zaragozafluye/2013/120501-milla-digita...', 2010, 2010, 2010, 'Siglo XXI', 'LA ALMOZARA', 41.65951700, -0.90727400, '0101000020E6100000F75AD07B6308EDBFF913950D6BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21062161003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21062161003.webp', 'https://www.flickr.com/photos/zaragozaantigua/21062161003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24066, 'Auditorio SGAE 2005', 'Recreaciâ”œâ”‚n virtual del barrio de La Almozara, centrada en el proyecto de auditorio de mâ”œâ•‘sica de la Sociedad General de Autores de Espaâ”œâ–’a (SGAE), presentado en abril de 2005 y previsto para 2008. Obra de Santiago Fajardo Cabeza, fue proyectado inicialmente para Pozuelo de Alarcâ”œâ”‚n. Serâ”œÂ¡a el mayor auditorio de Espaâ”œâ–’a, con capacidad para 16.500 personas y superficie construida de 25.000 metros cuadrados, en una parcela de 75.000. Albergarâ”œÂ¡a espectâ”œÃ­culos musicales de todo tipo, En mayo de 2005 fue descartado, tras ver duplicado mâ”œÃ­gicamente su millonario presupuesto inicial. En el solar se acondicionâ”œâ”‚ el Parking Sur de la Expo 2008, utilizado desde su clausura como rastro dominical. Fuente visual: www.santiagofajardo.com/auditorio-zaragoza/', 2005, 2005, 2005, 'Siglo XXI', 'LA ALMOZARA', 41.66277400, -0.91086100, '0101000020E61000009B75C6F7C525EDBFCE5147C7D5D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33467739262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33467739262.webp', 'https://www.flickr.com/photos/zaragozaantigua/33467739262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
